// ═══════════════════════════════════════════════════════
// Lookup Map
// ═══════════════════════════════════════════════════════

const TECHNIQUE_MAP = new Map<string, MITRETechnique>();
for (const t of TECHNIQUES) {
  TECHNIQUE_MAP.set(t.id, t);
}

/**
 * Look up a MITRE technique by ID.
 * Falls back to parent technique if sub-technique not found (e.g. T1055.001 → T1055).
 */
export function lookupMITRE(id: string): MITRETechnique | undefined {
  const direct = TECHNIQUE_MAP.get(id);
  if (direct) return direct;

  // Try parent technique (strip sub-technique)
  const dotIndex = id.indexOf('.');
  if (dotIndex > 0) {
    return TECHNIQUE_MAP.get(id.substring(0, dotIndex));
  }

  return undefined;
}

/**
 * Get all techniques in the database.
 */
export function getAllTechniques(): MITRETechnique[] {
  return TECHNIQUES;
}

/**
 * Get total technique count.
 */
export function getTechniqueCount(): number {
  return TECHNIQUES.length;
}
